example.code:
package apperror

import (
    "fmt"
    "net/http"
)

type AppError struct {
    Code       string `json:"code"`
    Message    string `json:"message"`
    HTTPStatus int    `json:"-"`
    Err        error  `json:"-"`
}

func (e *AppError) Error() string {
    if e.Err != nil {
        return fmt.Sprintf("%s: %v", e.Message, e.Err)
    }
    return e.Message
}

func (e *AppError) Unwrap() error { return e.Err }

// Constructor functions — never return package-level vars directly.
// Mutable package vars are a footgun: ErrNotFound.Message = "X" mutates the global.

func NewNotFound(resource string) *AppError {
    return &AppError{
        Code:       "NOT_FOUND",
        Message:    fmt.Sprintf("%s not found", resource),
        HTTPStatus: http.StatusNotFound,
    }
}

func NewUnauthorized(msg string) *AppError {
    return &AppError{Code: "UNAUTHORIZED", Message: msg, HTTPStatus: http.StatusUnauthorized}
}

func NewValidation(msg string) *AppError {
    return &AppError{Code: "VALIDATION_ERROR", Message: msg, HTTPStatus: http.StatusBadRequest}
}

// Wrap preserves HTTPStatus and Code from inner *AppError when present.
func Wrap(err error, msg string) *AppError {
    var inner *AppError
    if errors.As(err, &inner) {
        return &AppError{
            Code:       inner.Code,
            Message:    msg,
            HTTPStatus: inner.HTTPStatus,
            Err:        err,
        }
    }
    return &AppError{
        Code:       "INTERNAL_ERROR",
        Message:    msg,
        HTTPStatus: http.StatusInternalServerError,
        Err:        err,
    }
}
